// Build scoring prompt dynamically from config
const config = $('Load Industry Config').first().json;
const leads = $input.all();

// Build criteria text from config
const criteriaText = config.scoring.criteria
  .map(c => `- ${c.name.replace(/_/g, ' ')} (+${c.weight}): ${c.description}`)
  .join('\n');

// Format leads for prompt
const leadsForPrompt = leads.map((item, idx) => ({
  index: idx,
  id: item.json.id,
  name: item.json.fields['company name'] || item.json.fields['FULL NAME'] || 'Unknown',
  email: item.json.fields['EMAIL'] || null,
  phone: item.json.fields['Phone'] || null,
  city: item.json.fields['City'] || null,
  description: item.json.fields['COMPANY DESCRIPTION'] || null,
  size: item.json.fields['COMPANY SIZE'] || null,
  keywords: item.json.fields['KEYWORDS'] || null
}));

// Build the prompt
const prompt = `Score these ${leadsForPrompt.length} ${config.display_name} from 1-10 for outreach priority.

Scoring criteria:
${criteriaText}

Leads to score:
${leadsForPrompt.map(l => `[${l.index}] ${l.name} | ${l.city || 'Unknown city'} | ${l.email ? 'Has email' : 'No email'} | ${l.phone ? 'Has phone' : 'No phone'}`).join('\n')}

Return ONLY a valid JSON array with this exact format:
[{"index": 0, "score": 7, "reason": "brief reason"}, ...]

No other text, just the JSON array.`;

return {
  json: {
    leads: leadsForPrompt,
    prompt: prompt,
    config: config,
    model: config.scoring?.model || 'openai/gpt-4o-mini',
    system_prompt: config.scoring?.system_prompt || 'You are a lead scoring assistant. Score businesses 1-10 based on their potential value. Return ONLY valid JSON.'
  }
};

// Parse LLM response and map scores to leads
const response = $input.first().json;
const prevData = $('Format Batch Prompt').first().json;
const leads = prevData.leads;
const config = prevData.config;

// Get thresholds from config
const thresholds = config.scoring?.thresholds || { priority: 7, medium: 5, low: 0 };

let scores = [];
try {
  // Extract JSON from response
  const content = response.choices[0].message.content;

  // Try direct parse first
  try {
    scores = JSON.parse(content);
  } catch (e) {
    // Extract JSON array from text
    const match = content.match(/\[.*\]/s);
    if (match) {
      scores = JSON.parse(match[0]);
    }
  }
} catch (e) {
  console.error('Failed to parse scores:', e.message);
  return [];
}

// Map scores back to lead IDs with status based on thresholds
const results = scores.map(s => {
  const lead = leads.find(l => l.index === s.index);

  let status;
  if (s.score >= thresholds.priority) {
    status = 'READY';
  } else if (s.score >= thresholds.medium) {
    status = 'MEDIUM';
  } else {
    status = 'LOW_PRIORITY';
  }

  return {
    json: {
      id: lead?.id,
      score: s.score,
      reason: s.reason,
      status: status,
      industry: config.industry_id
    }
  };
});

console.log(`Scored ${results.length} leads: ${results.filter(r => r.json.status === 'READY').length} READY, ${results.filter(r => r.json.status === 'MEDIUM').length} MEDIUM, ${results.filter(r => r.json.status === 'LOW_PRIORITY').length} LOW_PRIORITY`);

return results;
